<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list ref="tgList" :listType="['List']" :IsShowAction="true" :showCheckBox="true"
            ModuleName="PROJECT" SubModuleCode="Task" IdentityColumn="USER_ID" :HeaderText="$t(this.NewTabName)"
            :LegendArray="[]" :ListData="ListingData" :HeaderData="Headers" :widgets="widgets" :HeaderButtons="Buttons"
            :TotalRecords="TotalRecords" :RenderRowActionMethod="renderActions" :isShowHeaderText="true"
            v-on:LeftsearchButtonClick="leftCommonSearch" :IsSearchFieldsOnTop="false" SearchPosition="top"
            :SearchFields="topsearchField" :ListDataCallBackFunction="FetchTeamListing" :SortExp="SortExp"
            :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')" v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata"
            v-on:ActionButtonClick="actionButtonClick" :Key="Key">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'Associate/DeAssociate' && data.row.USER_TYPE == 'User'">
                    <label class="switch w70" v-if="data.row.USER_TYPE == 'User' && logged_usertype != 'CL'">
                        <input v-bind:checked="data.row.STATUS_ID == 1001"
                            v-on:click="AssociateDeassociate($event, data.row)" name="is_billable"
                            class="form-check-input custom-control-input dynamic" type="checkbox" />
                        <span class="slider round" style="cursor:default;">
                            <span class="slider-yes">{{ $t('Yes') }}</span>
                            <span class="slider-no">{{ $t('No') }}</span>
                        </span>
                    </label>
                    <label v-if="data.row.USER_TYPE == 'Team' && logged_usertype != 'CL'" class="switch w70">
                        <input v-bind:checked="data.row.STATUS_ID == 1001"
                            v-on:click="AssociateDeassociateTeam(data.row)" name="is_billablee"
                            class="form-check-input custom-control-input dynamic" type="checkbox" />
                        <span class="slider round" style="cursor:default;">
                            <span class="slider-yes">{{ $t('Yes') }}</span>
                            <span class="slider-no">{{ $t('No') }}</span>
                        </span>
                    </label>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'Associate/DeAssociate' && data.row.USER_TYPE == 'Team'">
                    <span>N/A</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'LASTTRACKEDHOUR'">
                    {{ data.row.TRACK_HOURS ? data.row.TRACK_HOURS : 'N/A' }}
                </template>
                <template v-if="data.column.COLUMN_NAME == 'DEPARTMENT'">
                     <span style="white-space: nowrap;  word-wrap: break-word;  overflow: hidden;  display: block;  text-overflow: ellipsis;">
                        {{ data.row.ALIASNAME ? data.row.DEPARTMENT : 'N/A' }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'DESIGNATION_NAME'">
                     <span style="white-space: nowrap;  word-wrap: break-word;  overflow: hidden;  display: block;  text-overflow: ellipsis;">
                        {{ data.row.ALIASNAME ? data.row.DESIGNATION_NAME : 'N/A' }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'ALIASNAME'">
                    <span style="white-space: nowrap;  word-wrap: break-word;  overflow: hidden;  display: block;  text-overflow: ellipsis;">
                        {{ data.row.ALIAS_NAME ? data.row.ALIAS_NAME : 'N/A' }}
                    </span>                    
                </template>
                <template v-if="data.column.COLUMN_NAME == 'USER_NAME'">
                    <span
                        style="white-space: nowrap;  word-wrap: break-word;  overflow: hidden;  display: block;  text-overflow: ellipsis;">
                        <em v-if="data.row.USER_TYPE == 'User'" class="fa fa-user text-info"></em>
                        <em v-else class="fa fa-users text-primary"></em>
                        {{ data.row.USER_NAME ? data.row.USER_NAME : 'N/A' }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'RATE'">

                    <span
                        :title="$n(data.row.RATE ? data.row.RATE : 0, 'currency', $getLocaleByCurrency(projectCurrency))">
                        {{ $n(data.row.RATE ? data.row.RATE : 0, 'currency', $getLocaleByCurrency(projectCurrency))
                        }}</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'TRACK_HOURS'">
                    {{ data.row.TRACK_HOURS ? data.row.TRACK_HOURS : 'N/A' }}
                </template>
                <template v-if="data.column.COLUMN_NAME == 'coun_task_progress'">
                    <div class="user-count-wrapper">
                        <span v-if="data.row.USER_TYPE == 'User'">
                            <a class="text-dark single-action" href="javascript:;">
                                <em class="fa fa-tasks"></em>
                                <span class="noti-circle noti-green">{{ data.row.coun_task_progress.length > 0 ?
                                    data.row.coun_task_progress[0].count_assign_task : '0' }}</span>
                            </a>
                        </span>
                        <span v-else>
                            --
                        </span>
                    </div>

                </template>
            </template>
        </tg-list>
        
        <AddTeam v-if="IsAddTeamShow" :ProjectId="projectId" :Type="IsType" @close="IsAddTeamShow = false;"
            @callbackfunction="refreshTeamList" :NewTabName="NewTabName" :TabsArray="TabsArray"
            :projectCurrency="projectCurrency"></AddTeam>
        <EditTeam v-if="IsEditTeamShow" :ProjectId="projectId" :EditData="EditData" :NewTabName="NewTabName"
            :TabsArray="TabsArray"></EditTeam>
        <AssociateUserVue v-if="IsUser" :TeamId="TeamId" :TabsArray="TabsArray"></AssociateUserVue>

        <CreateTeam v-if="IsCreateTeamShow" @close="IsCreateTeamShow = false;"></CreateTeam>
    </section>
</template>

<script>
import DataService from '../../../../services/DataService.js';
import schema from '../../Project/ProjectDetailLeftAllTabs/ProjectTeamListingSchema.js';
import AddTeam from '../../../../components/Modal/AddTeam.vue';
import EditTeam from '../../../../components/Modal/EditTeam.vue';
import AssociateUserVue from '../../../../components/Modal/AssociateUser.vue';
import CreateTeam from '../../../../components/Modal/CreateTeam.vue';
export default {
    components: { AddTeam, EditTeam, AssociateUserVue, CreateTeam },
    props: {
        projectId: {
            type: Number,
            required: true
        },
        checkPmUser: {
            type: Boolean,
            required: true
        },
        NewTabName: {
            type: String,
            require: true
        },
        TabsArray: {
            type: Array
        },
        projectCurrency: {
            type: String
        }

    },
    data() {
        return {
            Key: 0,
            IsType: 'Team',
            TotalRecords: 0,
            isAssociated: false,
            noRecords: false,
            projectName: "",
            isLoading: false,
            CompanyId: null,
            PageSize: 10,
            PageNumber: 1,
            isPaged: 1,
            TotalPages: 0,
            widgets: [],
            SortBy: '',
            SortExp: '',
            taskId: '',
            Headers: schema.TableHeader,
            ListingData: [],
            searchCondition: '',
            Buttons: [],
            listActions: schema.listActions,
            EditData: [],
            ProjectTaskListingpopup: false,
            IsAddTeamShow: false,
            IsCreateTeamShow: false,
            IsEditTeamShow: false,
            logged_usertype: null,
            topsearchField: [
                {
                    fieldName: 'Enter  Name',
                    fieldType: "text",
                    fieldSearchConditionName: [''],
                    paramName: "UserName",
                    isSearch: true,
                    value: "",
                    listOptions: []
                },
            ],
            TeamData: [],
            IsUser: false,
            TeamId: 0,
            IsShowAction: true,
            Currency: '',
            UserType: ''
        }
    },
    watch: {       
        NewTabName: {
            handler(newTabName) {
                if (newTabName) {
                    this.updateButtons(newTabName);
                }
            },
            immediate: true
        }
    },
    created: function () {        
        var ths = this;
        ths.CompanyId = ths.GetUserInfo.CompanyId;
        ths.userId = ths.GetUserInfo.ID;        
        ths.logged_usertype = ths.GetUserInfo.UserType;
        this.Currency = this.GetUserInfo.Currency.replace(/[()]/g, '');
        if (!ths.Buttons || ths.Buttons.length === 0) {
            ths.Buttons = JSON.parse(JSON.stringify(schema.buttons));
        }
        if (ths.NewTabName) {
            ths.updateButtons(ths.NewTabName);
        }
        ths.ProjectOverview();
        ths.CheckDisabled();
        Promise.all([
            ths.FetchTeamListing(),
            ths.GetTeamForAssociateProject()
        ])
            .then(([users, teams]) => {                
                ths.ListingData = [...users, ...teams];
                ths.TotalRecords = ths.ListingData.length;
                ths.TotalPages = Math.ceil(ths.TotalRecords / ths.PageSize);
                ths.CurrentPage = ths.PageNumber;
                console.log("✅ Loaded records:", ths.TotalRecords);
            })
            .catch(err => {
                console.error("❌ Error loading data:", err);
            });
    },
    methods: {
        updateButtons(newTabName) {
            this.Headers[0].DISPLAY_NAME =this.$t(this.TabsArray.find(t => t.displayCode === "PROJECT_TEAM")?.displayName || 'Team');
            const buttonsCopy = JSON.parse(JSON.stringify(schema.buttons));
            if (newTabName && buttonsCopy && buttonsCopy.length > 0) {
                buttonsCopy.forEach((button, index) => {
                    if (button.callbackfunction === 'OpenAddTeamPopup') {
                        buttonsCopy[index].title = `${this.$t('Add')} ${this.$t(this.TabsArray.find(t => t.displayCode === "PROJECT_TEAM")?.displayName || 'Team')}`;
                    }
                    if (button.callbackfunction === 'CreateTeam') {
                        buttonsCopy[index].title = `${this.$t('Create')} ${this.$t(this.TabsArray.find(t => t.displayCode === "PROJECT_TEAM")?.displayName || 'Create')}`;
                    }
                });
            }
            this.Buttons = buttonsCopy;
        },
        CheckDisabled() {
            if ((this.logged_usertype == 'CL' || this.logged_usertype == 'NU') && this.checkPmUser) {
                this.Buttons[0].isvisible = true;               
                this.Buttons[2].isvisible = false;
            }
            else {
                if (this.logged_usertype == 'CA' || this.logged_usertype == 'PM') {
                    this.Buttons[0].isvisible = true;                   
                    this.Buttons[2].isvisible = false;
                }
                else {
                    this.Buttons[0].isvisible = false;                    
                    this.Buttons[2].isvisible = false;                  
                    this.Headers.forEach((element) => {
                        if (element.COLUMN_NAME == 'Associate/DeAssociate') {
                            element = element.VISIBLE = false;
                        }
                    });
                    this.IsShowAction = false;
                }

            }
        },
        async refreshTeamList() {
            this.isLoading = true;
            this.$emit('callbackWidgets');
            try {
                const [teamList, associateList] = await Promise.all([
                    this.FetchTeamListing(),
                    this.GetTeamForAssociateProject()
                ]);
                this.ListingData = [...teamList, ...associateList];
            } catch (err) {
                console.error(err);
            } finally {
                this.isLoading = false;
            }
        },
        ProjectOverview: async function () {
            var vm = this;
            var params = `projectId=${vm.projectId}`;
            await DataService.ProjectOverview(params).then(function (response) {
                if (response.data != null > 0) {
                    vm.projectName = response.data.projecT_NAME;
                }
            });
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'Work Diary':
                        action.isVisible = row.USER_TYPE == 'User' ? true : false;
                        break;
                    case 'Edit':
                        action.isVisible = row.USER_TYPE == 'User' ? true : false;
                        break;
                    case 'View Team':
                        action.isVisible = row.USER_TYPE == 'Team' ? true : false;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case 'WorkDiary':
                    this.WorkDiary(item)
                    break;
                case 'EditMember':
                    this.EditMember(item)
                    break;
                case 'ViewTeam':
                    this.AssignedUser(item.TEAM_USER_ID)
                    break;
            }
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchTeamListing();
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "Deletedata":
                    this.Deletedata();
                    break;
                case "OpenAddTeamPopup":
                    this.OpenAddTeamPopup();
                    break;                
                case "BackToList":
                    this.BackToList();
                    break;
                case "CreateTeam":
                    this.CreateTeam();
                    break;
            }
        },
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchTeamListing();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },
        Deletedata: async function () {
            var vm = this;
            var url = 'controller=Project&action=DeleteTeamMembers'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    var val = "";
                    $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                        if (val.length > 0)
                            val += ',';
                        val += $(this).val();
                    });
                    if (val.trim() != null) {
                        var checkUrl = `Ids=${val}&ProjectId=${vm.projectId}`;
                        vm.isLoading = true;
                        DataService.GetProjectTaskUsers(checkUrl).then(function (response) {
                            vm.isLoading = false;
                            if (response.data && response.data.status === "Success" && response.data.result.length > 0) {
                                let assignedUsers = response.data.result.map(x => x.full_name).join(", ");
                                let msg = response.data.result.length > 1
                                    ? `${vm.$t('Cannotdelete')} ${vm.$t('Theseusersareassignedtotasks')}: ${assignedUsers}`
                                    : `${vm.$t('Cannotdelete')} ${vm.$t('Thisuserisassignedtoatask')}: ${assignedUsers}`;

                                vm.ShowAlert(msg, "failure", true, vm.$t("Alert"));
                                return;
                            }
                            vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t(vm.TabsArray.find(t => t.displayCode === "PROJECT_TEAM")?.displayName || 'Team')), function () {
                                vm.isLoading = true;
                                var url = `Ids=${val}&ProjectId=${vm.projectId}`;
                                DataService.DeleteTeamMembers(url).then(function (response) {
                                    vm.isLoading = false;
                                    if (response.data != null) {
                                        vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t(vm.TabsArray.find(t => t.displayCode === "PROJECT_TEAM")?.displayName || 'Team')]), "success", true, vm.$t("Alert"));
                                        vm.refreshTeamList();
                                        vm.Key++;
                                    }
                                    else {
                                        vm.ShowAlert(vm.$t('DeletedError', [vm.$t(vm.TabsArray.find(t => t.displayCode === "PROJECT_TEAM")?.displayName || 'Team')]), "failure", true, vm.$t("Alert"));
                                    }
                                });
                            });
                        });

                    }
                    else {
                        vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
                    }
                } else {
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });

        },
        OpenAddTeamPopup: async function () {
            var ths = this;            
            var url = 'controller=Project&action=AddMemberInProject'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    ths.IsAddTeamShow = true;
                } else {
                    ths.ShowAlert(ths.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });

        },
        EditMember: async function (item) {
            var ths = this;
            var url = 'controller=Project&action=EditTeamMembers'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    ths.EditData = item;
                    ths.IsEditTeamShow = true;
                } else {
                    ths.ShowAlert(ths.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });

        },
        BackToList: function () {
            this.$router.push({ name: 'ProjectList' });
        },        
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (value.searchConditionJson != '') {
                this.searchCondition = value.searchConditionJson;
            } else {
                this.searchCondition = "";
            }
            if (value.searchConditionJson == "") {
                this.refreshTeamList();
            }
            this.FilterTeamListingRecord();
        },
        FilterTeamListingRecord() {
            var ths = this;
            var url = `projectId=${ths.projectId}&projectName=${ths.projectName}&designationId=&sortBy=${ths.SortBy}&sortExp=${ths.SortExp}&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&${ths.searchCondition}`;
            DataService.GetTeamListing(url).then((response) => {
                if (response.data?.result?.data?.length > 0) {
                    ths.ListingData = response.data?.result?.data;
                    ths.TotalRecords = response.data.result.data[0].Total_Count;
                    ths.TotalPages = Math.ceil(ths.TotalRecords / ths.PageSize);
                    ths.CurrentPage = ths.PageNumber;
                    ths.Buttons[2].isdisabled = true;
                } else {
                    ths.ListingData = [];
                    ths.TotalRecords = 0;
                    ths.TotalPages = Math.ceil(ths.TotalRecords / ths.PageSize);
                    ths.Buttons[2].isdisabled = true;
                }
            })
            ths.isLoading = false;
        },
        FetchTeamListing: function () {
            var ths = this;
            ths.isLoading = true;
            return new Promise((resolve, reject) => {
                let url = '';
                if (ths.searchCondition !== '') {
                    url = `projectId=${ths.projectId}&projectName=${ths.projectName}&designationId=&sortBy=${ths.SortBy}&sortExp=${ths.SortExp}&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&${ths.searchCondition}`;
                } else {
                    url = `projectId=${ths.projectId}&projectName=${ths.projectName}&designationId=&sortBy=${ths.SortBy}&sortExp=${ths.SortExp}&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}`;
                }
                DataService.GetTeamListing(url)
                    .then((response) => {
                        ths.isLoading = false;
                        if (response.data?.result?.data?.length > 0) {
                            response.data.result.data.forEach((element) => {
                                if (element.USER_ID == ths.userId) {
                                    element.isCheckBoxDisabled = true;
                                }
                            })
                            ths.TotalRecords = response.data.result.data[0].Total_Count;
                            ths.TotalPages = Math.ceil(ths.TotalRecords / ths.PageSize);
                            ths.CurrentPage = ths.PageNumber;
                            resolve(response.data.result.data);
                            ths.Buttons[2].isdisabled = true;
                        } else {
                            resolve([]);
                        }
                    })
                    .catch((error) => {
                        ths.isLoading = false;
                        reject(error);
                    });
            });
        },

        AssociateDeassociate: function (evt, item) {
            var vm = this;
            var membername = item.USER_NAME;
            var id = item.TEAM_PROJECT_ID;
            if (evt.target.checked) {
                vm.confirmR(vm.$t("ConfirmAssociate", [vm.$t(membername)]), true, vm.$t('Alert'), function () {
                    vm.isLoading = true;
                    var data = `id=${id}&type=A`;
                    DataService.AssociateDeassociate(data)
                        .then((response) => {
                            if (response.data.msg === 'success') {
                                vm.ShowAlert(vm.$t("TeamAssociateSuccess", [vm.$t(vm.NewTabName)]), 'success', true, vm.$t('Alert'));
                                vm.refreshTeamList();
                            } else {
                                vm.ShowAlert(vm.$t("ProcessingError"), 'failure', true, vm.$t('Alert'));
                            }
                        })
                        .finally(() => {
                            vm.refreshTeamList();
                            vm.isLoading = false;
                        });
                },
                    function () {
                        vm.$emit('callbackfunction');
                    }
                );
            } else {
                vm.confirmR([vm.$t("ConfirmDeAssociate", [vm.$t(membername)])], true, vm.$t('Alert'), function () {
                    vm.isLoading = true;
                    var data = `id=${id}&type=D`;
                    DataService.AssociateDeassociate(data)
                        .then((response) => {
                            if (response.data.msg === 'success') {
                                vm.ShowAlert(vm.$t("TeamDeassociateSuccess", [vm.$t(vm.NewTabName)]), 'success', true, vm.$t('Alert'));
                                vm.refreshTeamList();
                            } else {
                                vm.ShowAlert(vm.$t("ProcessingError"), 'failure', true, vm.$t('Alert'));
                            }
                        })
                        .finally(() => {
                            vm.refreshTeamList();
                            vm.isLoading = false;
                        });
                }, function () {
                    vm.$emit('callbackfunction');
                });
            }
        },
        GetTeamForAssociateProject() {
            var ths = this;
            return new Promise((resolve, reject) => {
                var url = `refId=${ths.projectId}&refCode=TEAM`;
                DataService.GetTeamForAssociateProject(url)
                    .then((response) => {
                        ths.isLoading = false;
                        if (response.data?.result?.length > 0) {
                            resolve(response.data.result);
                        } else {
                            resolve([]);
                        }
                    })
                    .catch((error) => {
                        ths.isLoading = false;
                        reject(error);
                    });
            });
        },
        AssignedUser(TeamId) {
            this.TeamId = TeamId;
            this.IsUser = true;
        },
        AssociateDeassociateTeam(data) {
            var vm = this;
            vm.confirmR(vm.$t("ConfirmAssociate", [(vm.$t(data.USER_NAME))]), true, vm.$t("Alert"), function () {
                var postJSON = {
                    ids: data.USER_ID,
                    moduleName: "PROJECT",
                    subModuleCode: "TEAM",
                    refCode: 'TALYGEN_PROJECT_TEAMS'
                };
                var objectPostString = JSON.stringify(postJSON);
                DataService.CommonCommonDelete(objectPostString).then(function (response) {
                    vm.isLoading = false;
                    if (response.status == 200) {
                        vm.ShowAlert(vm.$t('TeamDeassociateSuccess', [vm.$t(vm.NewTabName)]), "success", true, vm.$t("Alert"));
                        vm.ListingData = vm.ListingData.filter(item => item.USER_ID !== data.USER_ID);

                    }
                    else {
                        vm.ShowAlert(vm.$t("ProcessingError"), 'failure', true, vm.$t('Alert'));
                    }
                });
            });
        },
        WorkDiary(data) {
            var vm = this;
            vm.$router.push(`/WorkDiary/Index/${data.USER_ID}/${data.PROJECT_ID}`);
        },
        CreateTeam() {            
            var vm = this;
            vm.IsCreateTeamShow = true;
        }

    }
}
</script>
<style>
.edit-action {
    margin-left: 6px;
}

#USER_NAME {
    width: 120px;
}
.modal-backdrop.show {
    opacity: 0 !important;
}
</style>