<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('Create') }} {{ $t(dynamictabname) }}</h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>
                    <div class="modal-body">
                        <loader :is-visible="isLoading"></loader>
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AddTeamForm"
                            :mandatorytext='MandatoryString' v-on:OnSubmit="OnSubmit">
                        </dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../services/DataService';
export default
    {

        data() {
            return {
                isLoading: false,
                ProjectBackLogId: 0,
                MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
                FormSchema: [
                    {
                        layoutType: "double",
                        Data: [
                            {
                                astype: "TextField",
                                label: this.$t('TeamName'),
                                name: "TeamName",
                                value: "",
                                placeholder: this.$t('Enter Team Name'),
                                validationRules: { "required": true, max: 100 },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t('TeamUser'),
                                name: "TeamUsers",
                                mode: "tag",
                                value: "",
                                config: {
                                    options: []
                                },
                                placeholder: this.$t('Team User'),
                                validationRules: { "required": true, max: 100 },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t('TeamLead'),
                                name: "TeamLead",
                                value: "",
                                mode: "tag",
                                config: {
                                    options: []
                                },
                                placeholder: this.$t('Team Lead'),
                                validationRules: { "required": true, max: 100 },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t('Skill'),
                                name: "Skill",
                                mode: "tag",
                                value: "",
                                config: {
                                    options: []
                                },
                                placeholder: this.$t('Select Skill'),
                                validationRules: { "required": false, max: 100 },
                            },
                            {
                                astype: "toggleField",
                                label: this.$t('GlobalTeam'),
                                name: "GlobalTeam",
                                value: "",
                                config: {
                                    options: [],
                                    onChange: this.onChangeGlobalTeam
                                },
                                validationRules: { "required": false, max: 100 },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t('TeamAssociate'),
                                name: "User",
                                value: "",
                                visibility: true,
                                config: {
                                    options: []
                                },
                                placeholder: this.$t('Select Team Associate'),
                                validationRules: { "required": true, max: 100 },
                            }
                        ]
                    }
                ],
                buttons: [
                    {
                        type: "submit",
                        class: "btn btn-success",
                        text: "<i class='fa fa-save pr-2'></i>Save",
                        isVisible: true
                    },
                    {
                        type: "button",
                        class: "btn btn-danger",
                        text: "<i class='fa fa-close pr-2'></i>Cancel",
                        onClick: this.Close,
                    },
                ],
                projectId: null,
                TeamMemberData: [],
                UserId: 0,
                NewTeamId: 0,
                UserList: [],
                SkillData: [],
                ModuleData: []
            }
        },
        created: async function () {
            debugger
            var vm = this;
            vm.isLoading = true;
            await vm.GetUser();
            await vm.GetSkill();
            await vm.TeamAssociate();
            if (vm.TeamId != null) {
                setTimeout(function () {
                    vm.BindTeamDeatils();
                }, 1000);
            }
            vm.isLoading = false;
        },
        methods: {
            Close() {
                this.$emit("close");
            },
            async GetUser() {
                var vm = this;
                var url = `id=&moduleName=&type=TEAM_USER_LIST&search=&refId=`;
                await DataService.GetDDLData(url).then((response) => {
                    if (response.status == 200) {
                        if (response.data.DATA != undefined || response.data.DATA != null) {
                            if (response.data.DATA.length > 0) {
                                vm.UserList = response.data.DATA;
                                debugger
                                vm.UserList.forEach(item => {
                                    let obj = {
                                        value: item.value,
                                        name: item.name
                                    };
                                    vm.FormSchema[0].Data[1].config.options.push(obj);
                                    vm.FormSchema[0].Data[2].config.options.push(obj);
                                })
                                vm.$refs.AddTeamForm.UpdateKeyValue();
                            }
                        }
                    }
                })
            },
            async GetSkill() {
                var vm = this;
                var url = `id=&moduleName=&type=USER_SKILLS&search=&refId=`;
                await DataService.GetDDLData(url).then((response) => {
                    if (response.status == 200) {
                        if (response.data.DATA != undefined || response.data.DATA != null) {
                            if (response.data.DATA.length > 0) {
                                vm.SkillData = response.data.DATA;
                                vm.SkillData.forEach(item => {
                                    let obj = {
                                        value: item.value,
                                        name: item.name
                                    };
                                    vm.FormSchema[0].Data[3].config.options.push(obj);
                                })
                                vm.$refs.AddTeamForm.UpdateKeyValue();
                            }
                        }
                    }
                })
            },
            async TeamAssociate() {
                debugger
                var vm = this;
                var url = `id=&moduleName=&type=PHASE_TYPE&search=&refId=`;
                await DataService.GetDDLData(url).then((response) => {
                    if (response.status == 200) {
                        if (response.data.DATA != undefined || response.data.DATA != null) {
                            if (response.data.DATA.length > 0) {
                                vm.ModuleData = response.data.DATA;
                                vm.ModuleData.forEach(item => {
                                    let obj = {
                                        value: item.value,
                                        name: item.name
                                    };
                                    vm.FormSchema[0].Data[5].config.options.push(obj);
                                })
                                var defaultItem = vm.ModuleData.find(item => item.name.toLowerCase() === 'project');
                                if (defaultItem) {
                                    vm.FormSchema[0].Data[5].value = defaultItem.value;
                                }
                                vm.$refs.AddTeamForm.UpdateKeyValue();
                            }
                        }
                    }
                })
            },
            OnSubmit: async function () {
                
                var ths = this;
                ths.isLoading = true;
                var val = "";
                var UserVal = "";
                var TeamLead = "";
                ths.FormSchema[0].Data[3].value.forEach((itm) => {
                    val += itm.value;
                    val += ',';
                });
                ths.FormSchema[0].Data[1].value.forEach((itm) => {
                    UserVal += itm.value;
                    UserVal += ',';
                });
                ths.FormSchema[0].Data[2].value.forEach((itm) => {
                    TeamLead += itm.value;
                    TeamLead += ',';
                });
                // Convert to arrays (avoid trailing commas)
                let userArr = UserVal.split(',').filter(x => x);
                let teamLeadArr = TeamLead.split(',').filter(x => x);

                // ✅ Remove TeamLead values from UserVal
                userArr = userArr.filter(id => !teamLeadArr.includes(id));

                // Convert back to comma-separated string
                UserVal = userArr.join(',');
                TeamLead = teamLeadArr.join(',');
                
                var obj = {
                    TeamId: ths.NewTeamId,
                    Type: 'Team',
                    TeamName: ths.FormSchema[0].Data[0].value,
                    TeamUser: UserVal,
                    TeamLeadId: TeamLead,
                    UserId: ths.UserId,
                    SkillId: val,
                    GlobalTeam: ths.FormSchema[0].Data[4].value,
                    ModuleId: ths.FormSchema[0].Data[4].value == true ? 0 : ths.FormSchema[0].Data[5].value,
                    StatusId: 1001
                }
                await DataService.SaveTeam(JSON.stringify(obj)).then(function (response) {
                    ths.isLoading = false;
                    if (response.data.result.DATA.length > 0) {
                        if (response.data.result.DATA[0].VALUE == 'TEAM_UPDATED') {
                            ths.ShowAlert(ths.$t('UpdatedSuccess', [ths.$t('Team')]), "success", true, ths.$t("Alert"));
                            ths.Close();
                            
                        }
                        else if (response.data.result.DATA[0].VALUE == 'TEAM_EXISTS') {
                            ths.ShowAlert(ths.$t('AlreadyExists', [ths.$t('Team memeber')]), "warning", true, ths.$t("Alert"));
                        }
                        else {
                            ths.ShowAlert(ths.$t('AddedSuccess', [ths.$t('Team ')]), "success", true, ths.$t("Alert"));
                            ths.Close();
                            
                        }
                    } else {
                        ths.ShowAlert(ths.$t("UnknownErrorOccur"), "failure", true, ths.$t('Alert'));
                    }
                })
            },
            onChangeGlobalTeam(e, field) {
                
                var vm = this;
                if (field.value) {
                    vm.FormSchema[0].Data[5].visibility = false;
                    vm.FormSchema[0].Data[5].validationRules.required = false;
                } else {
                    vm.FormSchema[0].Data[5].visibility = true;
                    vm.FormSchema[0].Data[5].validationRules.required = true;
                }
            },
            BindTeamDeatils() {
                
                var vm = this;
                vm.NewTeamId = vm.TeamId.team_id;
                vm.FormSchema[0].Data[0].value = vm.TeamId.Team_name;
                const userIdArray = vm.TeamId.UserId.split(',');
                var UserSelect = vm.UserList.filter(item => userIdArray.includes(item.value))
                const LeadArrayy = vm.TeamId.Team_Lead_Id.split(',');
                var LeadSelect = vm.UserList.filter(item => LeadArrayy.includes(item.value))
                var result = vm.UserList.filter(value => !UserSelect.includes(value) && !LeadSelect.includes(value));
                // vm.FormSchema[0].Data[1].config.options=[];
                // vm.FormSchema[0].Data[2].config.options=[];
                // result.forEach((item)=>{
                //     let obj={
                //         value:item.value,
                //         name:item.name
                //     };
                //     vm.FormSchema[0].Data[1].config.options.push(obj);
                //     vm.FormSchema[0].Data[2].config.options.push(obj);
                // })
                var UserData = [];
                UserSelect.forEach((itm) => {
                    var obj = {
                        value: itm.value,
                        label: itm.name
                    }
                    UserData.push(obj);
                    //vm.FormSchema[0].Data[2].config.options.push(obj);
                })
                vm.FormSchema[0].Data[1].value = UserData;
                var LeadData = [];
                LeadSelect.forEach((itm) => {
                    var obj = {
                        value: itm.value,
                        label: itm.name
                    }
                    LeadData.push(obj);
                    //vm.FormSchema[0].Data[1].config.options.push(obj);
                })
                vm.FormSchema[0].Data[2].value = LeadData;
                if (vm.TeamId.SkilsName != undefined && vm.TeamId.SkilsName != null) {
                    const userIdArrayyy = vm.TeamId.SkilsName.split(',');
                    var SkillSelect = vm.SkillData.filter(item => userIdArrayyy.includes(item.name))
                    var SkillData = [];
                    SkillSelect.forEach((itm) => {
                        var obj = {
                            value: itm.value,
                            label: itm.name
                        }
                        SkillData.push(obj);
                    })
                    vm.FormSchema[0].Data[3].value = SkillData;
                }
                vm.FormSchema[0].Data[4].value = vm.TeamId.is_global;
                if (vm.TeamId.is_global) {
                    vm.FormSchema[0].Data[5].visibility = false;
                } else {
                    vm.FormSchema[0].Data[5].visibility = true;
                    const ModuleArrayy = vm.TeamId.Module_name;
                    var ModuleSelect = vm.ModuleData.filter(item => ModuleArrayy.includes(item.name))
                    vm.FormSchema[0].Data[5].value = ModuleSelect[0].value;
                }
            }

        }
    }
</script>
